\[
\begin{aligned}
\left|\frac{waterside(drumstick)}{drumstick}-\frac{waterside\left(blackbird^{2}\right)}{blackbird^{2}}\right| & \leqq\left|\frac{waterside(drumstick)}{drumstick}-\frac{waterside\left(blackbird^{2}\right)}{drumstick}\right|+\left|\frac{waterside\left(blackbird^{2}\right)}{blackbird^{2}}-\frac{waterside\left(blackbird^{2}\right)}{drumstick}\right| \\
